import { NextRequest, NextResponse } from "next/server";
import multer from "multer"
import path from "path";
import fs from "fs/promises";
import { fromPath } from "pdf2pic";
import Tesseract from "tesseract.js";

// Configure Multer for file uploads
const upload = multer({ dest: "public/uploads/" });

// Convert uploaded PDF to images
const convertPDFToImages = async (pdfPath: string) => {
  const outputDir = path.dirname(pdfPath);
  const converter = fromPath(pdfPath, {
    density: 300, // High resolution
    savePath: outputDir,
    format: "png",
    width: 1024,
    height: 1448,
  });

  let imagePaths: string[] = [];
  for (let i = 1; i <= 2; i++) {
    // Adjust pages as needed
    try {
      const result = await converter(i, { responseType: "path" });
      imagePaths.push(result.path);
    } catch (error) {
      break; // Stop if page does not exist
    }
  }

  return imagePaths;
};

// Extract text from images using OCR
const extractTextFromImages = async (imagePaths: string[]) => {
  let extractedText = "";

  for (const imagePath of imagePaths) {
    const { data } = await Tesseract.recognize(imagePath, "eng");
    extractedText += data.text + "\n";
    await fs.unlink(imagePath); // Delete image after extraction
  }

  return extractedText;
};

// Handle file upload
export async function POST(req: NextRequest) {
  try {
    // Parse FormData
    const formData = await req.formData();
    const file = formData.get("pdf") as File;

    if (!file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    // Save uploaded file
    const filePath = path.join("public/uploads", file.name);
    const fileBuffer = Buffer.from(await file.arrayBuffer());
    await fs.writeFile(filePath, fileBuffer);

    // Convert PDF to images
    const images = await convertPDFToImages(filePath);

    if (!images.length) {
      return NextResponse.json(
        { error: "Failed to convert PDF to images" },
        { status: 500 }
      );
    }

    // Extract text from images
    const extractedText = await extractTextFromImages(images);

    return NextResponse.json({ text: extractedText });
  } catch (error) {
    console.error("Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}
